import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.EncodingException;

public class XSSFixedCode {
    public static void main(String[] args) {
        // Simulating user input - this would typically come from a user input form or some external source
        String userInput = "<script>alert('XSS Vulnerability!')</script>";

        // Properly handling user input by escaping it before printing to the output
        String escapedInput = null;
        try {
            escapedInput = ESAPI.encoder().encodeForHTML(userInput);
            System.out.println("User input: " + escapedInput);
        } catch (EncodingException e) {
            System.out.println("Error while encoding user input: " + e.getMessage());
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
